"""
relay_voice_bridge — 传话 → 语音桥接节点
订阅 aipet/relay_voice，调用 ros2 action send_goal CLI 播报
"""
import rclpy
from rclpy.node import Node
from std_msgs.msg import String
import subprocess
import os
import threading


class RelayVoiceBridge(Node):
    def __init__(self):
        super().__init__('relay_voice_bridge')

        self._sub = self.create_subscription(
            String, 'aipet/relay_voice', self._on_voice, 10
        )
        self._env = os.environ.copy()

        self.get_logger().info('🔊 传话语音桥接已启动（CLI 持久模式）')

    def _on_voice(self, msg):
        content = msg.data
        if not content:
            return
        self.get_logger().info(f'🔊 语音播报: {content[:50]}')
        threading.Thread(target=self._speak, args=(content,), daemon=True).start()

    def _speak(self, content):
        cmd = [
            'ros2', 'action', 'send_goal',
            '/voice/speak', 'robot_voice_bridge/action/Speak',
            f"{{text: '{content}'}}",
        ]
        try:
            # 先用 5s 确认是否被接受
            r = subprocess.run(cmd, env=self._env, capture_output=True, text=True, timeout=5)
            out = r.stdout + r.stderr
            if 'Goal was rejected' in out:
                self.get_logger().warn('❌ Action 被拒绝')
            elif 'Goal accepted' in out:
                self.get_logger().info('✅ Action 已接受')
            else:
                self.get_logger().warn(f'⚠️ {out[:150]}')
        except subprocess.TimeoutExpired:
            # 5s 超时 = 接受且正在播放中
            self.get_logger().info('✅ Action 已接受，播放中...')
        except FileNotFoundError:
            self.get_logger().error('❌ ros2 命令未找到')


def main(args=None):
    rclpy.init(args=args)
    node = RelayVoiceBridge()
    try:
        rclpy.spin(node)
    except KeyboardInterrupt:
        pass
    finally:
        node.destroy_node()
        rclpy.shutdown()


if __name__ == '__main__':
    main()
